SELECT bs."in.comstock_building_type" AS comstock_building_type, count(DISTINCT (bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state)) AS sample_count, (count(DISTINCT (bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state)) * sum(bs.weight)) / CAST(sum(1) AS DECIMAL) AS units_count, sum(ts_aggr._inner_rows) / CAST(count(DISTINCT (bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state)) AS DECIMAL) AS rows_per_sample, sum(ts_aggr."bs__out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption__baseline", sum(ts_aggr."up__out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption__upgrade", sum((coalesce(ts_aggr."bs__out.electricity.total.energy_consumption", 0) - coalesce(ts_aggr."up__out.electricity.total.energy_consumption", 0)) * bs.weight) AS "electricity.total.energy_consumption__savings", sum(ts_aggr."bs__out.natural_gas.total.energy_consumption" * bs.weight) AS "natural_gas.total.energy_consumption__baseline", sum(ts_aggr."up__out.natural_gas.total.energy_consumption" * bs.weight) AS "natural_gas.total.energy_consumption__upgrade", sum((coalesce(ts_aggr."bs__out.natural_gas.total.energy_consumption", 0) - coalesce(ts_aggr."up__out.natural_gas.total.energy_consumption", 0)) * bs.weight) AS "natural_gas.total.energy_consumption__savings" FROM (SELECT ts_flat.state AS state, ts_flat.timestamp AS timestamp, ts_flat.bldg_id AS bldg_id, sum(ts_flat."_v__out.electricity.total.energy_consumption") FILTER (WHERE ts_flat.upgrade = 0) AS "bs__out.electricity.total.energy_consumption", sum(ts_flat."_v__out.electricity.total.energy_consumption") FILTER (WHERE ts_flat.upgrade = 1) AS "up__out.electricity.total.energy_consumption", sum(ts_flat."_v__out.natural_gas.total.energy_consumption") FILTER (WHERE ts_flat.upgrade = 0) AS "bs__out.natural_gas.total.energy_consumption", sum(ts_flat."_v__out.natural_gas.total.energy_consumption") FILTER (WHERE ts_flat.upgrade = 1) AS "up__out.natural_gas.total.energy_consumption", count(*) FILTER (WHERE ts_flat.upgrade = 0) AS _inner_rows FROM (SELECT comstock_amy2018_r2_2025_ts_by_state.state AS state, comstock_amy2018_r2_2025_ts_by_state.bldg_id AS bldg_id, date_trunc('year', date_add('second', -900, comstock_amy2018_r2_2025_ts_by_state.timestamp)) AS timestamp, comstock_amy2018_r2_2025_ts_by_state.upgrade AS upgrade, comstock_amy2018_r2_2025_ts_by_state."out.electricity.total.energy_consumption" AS "_v__out.electricity.total.energy_consumption", comstock_amy2018_r2_2025_ts_by_state."out.natural_gas.total.energy_consumption" AS "_v__out.natural_gas.total.energy_consumption" FROM comstock_amy2018_r2_2025_ts_by_state WHERE comstock_amy2018_r2_2025_ts_by_state.upgrade IN (0, 1) AND comstock_amy2018_r2_2025_ts_by_state.state IN ('CO', 'NM') AND (comstock_amy2018_r2_2025_ts_by_state.bldg_id, comstock_amy2018_r2_2025_ts_by_state.state) IN (SELECT bs.bldg_id, bs.state FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS bs WHERE bs.upgrade IN (1) AND bs.applicability = true GROUP BY bs.bldg_id, bs.state HAVING count(distinct(bs.upgrade)) = 1)) AS ts_flat GROUP BY ts_flat.state, ts_flat.timestamp, ts_flat.bldg_id) AS ts_aggr JOIN comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS bs ON bs.bldg_id = ts_aggr.bldg_id AND bs.state = ts_aggr.state AND bs.upgrade = 0 AND bs.state IN ('CO', 'NM') GROUP BY 1 ORDER BY 1